        Ok::<_, String>(final_status)
    }));

    match result {
        Ok(Ok(status)) => {
            eprintln!("[ok] execution completed, status={:?}", status);
            ExitCode::SUCCESS
        }
        Ok(Err(msg)) => {
            eprintln!("[err] {}", msg);
            ExitCode::from(1)
        }
        Err(panic) => {
            let msg = if let Some(s) = panic.downcast_ref::<String>() {
                s.clone()
            } else if let Some(s) = panic.downcast_ref::<&str>() {
                s.to_string()
            } else {
