pub(crate) fn warn_fn(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: int n = lua_gettop(L);
    let n = state.top();
    // C: luaL_checkstring(L, 1);  /* at least one argument */
    state.check_arg_string(1)?;
    // C: for (i = 2; i <= n; i++) luaL_checkstring(L, i);
