        state.warning(&s, true)?;
    }
    // C: lua_warning(L, lua_tostring(L, n), 0);  /* close warning */
    let s: Vec<u8> = state
        .to_lua_string_bytes(n)
        .map(|b| b.to_vec())
        .unwrap_or_default();
    state.warning(&s, false)?;
    Ok(0)
