            None => {
                if lua_vm::api::is_number(self, arg) {
                    Err(LuaError::arg_error(
                        arg,
                        "number has no integer representation",
                    ))
                } else {
                    let got = self.value_at(arg);
                    Err(LuaError::type_arg_error(arg, "number", &got))
                }
            }
        }
    }

