    fn ensure_stack<S: AsRef<[u8]> + ?Sized>(&mut self, n: i32, msg: &S) -> Result<(), LuaError> {
        if lua_vm::api::check_stack(self, n) {
            return Ok(());
        }
        let m = msg.as_ref();
        if m.is_empty() {
            Err(LuaError::runtime(format_args!("stack overflow")))
        } else {
            Err(LuaError::runtime(format_args!(
                "stack overflow ({})",
                StubBStr(m)
